import React from "react";

const NosotrosSection = () => {
  return (
    <section
      style={{
        display: "flex",
        alignItems: "center",
        gap: "2rem",
        maxWidth: "1200px",
        margin: "0 auto 5rem",
        flexWrap: "wrap",
        padding: "0 1rem",
      }}
    >
      <div style={{ flex: 1, minWidth: "300px" }}>
        <h1
          style={{
            fontSize: "3rem",
            fontWeight: "900",
            marginBottom: "1rem",
            color: "#003E73",
          }}
        >
          Nice to meet you
        </h1>
        <p
          style={{
            fontSize: "1.25rem",
            lineHeight: "1.7",
            color: "#003E73",
          }}
        >
          We're John and Jai, co-founders of Hydrant. Our journey started when both
          us (John, a scientist, and Jai, a finance consultant) were trying to solve
          the same problem on opposite sides of the US. After a friend connected us,
          the rest is history.
        </p>
      </div>

      <div
        style={{ flex: 1, minWidth: "300px", textAlign: "center" }}
      >
        <img
          src={require("../../assets/quien-contra-nosotros.jpg")}
          alt="Cargando..."
          style={{ maxWidth: "100%", borderRadius: "1rem" }}
        />
      </div>
    </section>
  );
};

export default NosotrosSection;
